module full_adder(
    input A,
    input B,
    input CIN,
    output SUM,
    output COUT
);

wire w1, w2, w3;

// Calculate SUM
wire __w1_tmp = A ^ B;
assign w1 = __w1_tmp;
assign SUM = w1 ^ CIN;

// Calculate COUT
assign w2 = A & B;
assign w3 = CIN & w1;
assign COUT = w2 | w3;

endmodule
